            if ((visited & (1 << neighbor)) == 0) {
                // If the neighbor is not visited, we can go to it
                long long new_visited = visited | (1 << neighbor);
                long long current_len = dfs(neighbor, new_visited);
                max_len = max(max_len, current_len);
            }
        }

        memo[key] = max_len;
        return max_len;
    };

    // Try all starting nodes
    long long result = 0;
    for (long long i = 0; i < n; ++i) {
        long long visited = 1 << i;
        result = max(result, dfs(i, visited));
    }

    return result;
}

